import pytest
from factorial import factorial

# Happy path: typical positive integers
def test_factorial_two():
    assert factorial(2) == 2

def test_factorial_three():
    assert factorial(3) == 6

def test_factorial_five():
    assert factorial(5) == 120

def test_factorial_ten():
    assert factorial(10) == 3628800

# Edge cases: n = 0 and n = 1
def test_factorial_zero():
    assert factorial(0) == 1

def test_factorial_one():
    assert factorial(1) == 1

# Edge case: large n that still fits within recursion limit
def test_factorial_twenty():
    assert factorial(20) == 2432902008176640000

# Edge case: n that exceeds default recursion depth
def test_factorial_recursion_depth():
    with pytest.raises(RecursionError):
        factorial(1000)

# Error case: negative integer
def test_factorial_negative():
    with pytest.raises(ValueError, match="n must be non-negative"):
        factorial(-1)

def test_factorial_negative_large():
    with pytest.raises(ValueError, match="n must be non-negative"):
        factorial(-100)

# Error case: non-integer input (string)
def test_factorial_string():
    with pytest.raises(TypeError):
        factorial("5")

# Error case: non-integer input (float that is not an integer value)
def test_factorial_float():
    with pytest.raises(TypeError):
        factorial(5.5)
